// Solution
#include <iostream> 
#include <vector> 
using namespace std; 

struct Node { int value; Node* left; Node* right; }; 

class Solution { 
public: 
    int height(Node* root) { 
        if (root == nullptr) { 
            return 0; 
        } else { 
            int leftHeight = height(root->left); 
            int rightHeight = height(root->right); 
            return 1 + max(leftHeight, rightHeight); 
        } 
    } 
};

